import java.util.Scanner;

public class SecureBuffer {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        int bufferSize = 10; // Define buffer size
        char[] buffer = new char[bufferSize]; // Buffer of fixed size

        if (userInput.length() > bufferSize) {
            System.out.println("Input exceeds buffer size. Please enter a shorter string.");
        } else {
            userInput.getChars(0, userInput.length(), buffer, 0);

            System.out.println("User input copied into buffer: " + String.valueOf(buffer));
        }
    }
}

### Explanation:
취약유형: Buffer Overflow
